/** The numbered checklist items as `{ num, text }` (text excludes the number). */
function checklistItems(): { num: string; text: string }[] {
  return (CHECKLIST.match(/^\d+(?:\.\d+)?\. .+$/gm) ?? []).map((line) => {
    const m = line.match(/^(\d+(?:\.\d+)?)\. (.*)$/);
    return { num: m![1], text: m![2] };
  });
}

const ITEMS = checklistItems();

/** Find a checklist item whose bold label (e.g. `**Download**`) is `label`. */
function itemByLabel(label: string): { num: string; text: string } | undefined {
  return ITEMS.find((i) => i.text.trim().startsWith(`**${label}**`));
}

/**
 * Whether `haystack` references the per-row "⋮" actions trigger, accepting the
 * literal glyph or any of its common textual aliases (so a faithful paraphrase
 * still passes while the stale "inline control" wording fails).
 */
function mentionsEllipsisTrigger(haystack: string): boolean {
  const h = haystack.toLowerCase();
  return (
    haystack.includes(VERTICAL_ELLIPSIS) ||
    h.includes('vertical ellipsis') ||
    h.includes('three-dot') ||
    h.includes('three dot') ||
    h.includes('kebab')
  );
}

/** Whether an action's checklist item describes reaching it via the row menu. */
function actionReachedViaMenu(itemText: string): boolean {
  const h = itemText.toLowerCase();
  // The action must be presented as something reached by opening the row menu
  // (the ⋮ glyph, the word "menu", or "dropdown"), NOT as an inline,
  // always-visible control in the row.
  return itemText.includes(VERTICAL_ELLIPSIS) || h.includes('menu') || h.includes('dropdown');
}

/* ===========================================================================
 * The checklist section exists
 * ========================================================================= */
describe('README "Final End-to-End Verification Checklist" section', () => {
  it('exists', () => {
    expect(checklistStart, 'README must contain the checklist heading').toBeGreaterThanOrEqual(0);
    expect(CHECKLIST.length, 'the checklist section must be non-empty').toBeGreaterThan(0);
  });
});

/* ===========================================================================
 * The checklist must describe the new ⋮ dropdown / right-click row menu
 *
 * The old checklist's item 7 said "entries render in the table with Name, Size,
 * Modified, and Actions columns" (the header is actually blank and the controls
 * are no longer inline), and items 9–12 described "clicking the Download link"
 * / "Delete action" as if directly visible in the row. None of the new
 * interactions (⋮ button, hover-reveal, right-click, blank header) were
 * mentioned anywhere.
 * ========================================================================= */
describe('checklist describes the ⋮ dropdown / right-click row menu', () => {
  it('references the per-row "⋮" actions trigger (the new primary interaction)', () => {
    expect(
      mentionsEllipsisTrigger(CHECKLIST),
      'the checklist must reference the per-row "⋮" actions button — it is the new primary ' +
        'way to reach Download/Delete/Move/Copy, but the old checklist described inline controls',
    ).toBe(true);
  });

  it('mentions right-click as an alternative way to open the row menu', () => {
    expect(
      CHECKLIST.toLowerCase().includes('right-click'),
      'the checklist must mention that right-clicking a row also opens the actions menu — ' +
        'a core interaction the old checklist omitted entirely',
    ).toBe(true);
  });

  it('notes the ⋮ button is revealed on row hover', () => {
    expect(
      CHECKLIST.toLowerCase().includes('hover'),
      'the checklist must note the "⋮" button is revealed on row hover — otherwise a reviewer ' +
        'would not see the control and could wrongly conclude the feature is missing',
    ).toBe(true);
  });

  it('states the Actions column header is intentionally blank', () => {
    expect(
      CHECKLIST.toLowerCase().includes('blank'),
      'the Actions column header is now an empty <th>; the checklist must describe it as blank ' +
        'rather than as a labelled "Actions" column header',
    ).toBe(true);
  });

  it('documents that the row menu closes (Escape / click elsewhere) and only one is open at a time', () => {
    expect(
      CHECKLIST.toLowerCase().includes('escape'),
      'the checklist must document that the row menu can be closed (e.g. pressing Escape or ' +
        'clicking elsewhere) — part of the row-menu interaction the README omits',
    ).toBe(true);

    const lower = CHECKLIST.toLowerCase();
    expect(
      lower.includes('only one') || lower.includes('one menu'),
      'the checklist must document the "only one menu open at a time" invariant',
    ).toBe(true);
  });
});

/* ===========================================================================
 * Items 9–12: each action is reached via the ⋮ menu, not an inline control
 * ========================================================================= */
describe('checklist Download/Delete/Move/Copy items reference the ⋮ menu', () => {
  it.each([['Download'], ['Delete'], ['Move'], ['Copy']])(
    '%s item describes opening the "⋮" menu (not an inline control)',
    (action) => {
      const item = itemByLabel(action);
      expect(item, `the checklist must have a "${action}" item`).toBeDefined();
      expect(
        actionReachedViaMenu(item!.text),
        `the "${action}" checklist item must describe opening the "⋮" menu / dropdown, not an ` +
          `inline control such as "clicking the ${action} link"`,
      ).toBe(true);
    },
  );

  it('does NOT describe an inline "Download link" clicked directly in the row', () => {
    // The single most misleading stale phrase: it points a reviewer at a
    // control that no longer exists in the row.
    expect(
      CHECKLIST.toLowerCase().includes('clicking the download link'),
      'the checklist must not say "clicking the Download link" — that control no longer exists ' +
        'inline; it lives behind the "⋮" menu',
    ).toBe(false);
  });
});

/* ===========================================================================
 * The fix is targeted: unaffected checklist items + table columns remain
 *
 * The finding instructs a targeted, minimal change. These guard against the
 * checklist being rewritten in a way that drops unrelated content (the build /
 * test / API / Search steps, and the Name/Size/Modified columns which are
 * unchanged).
 * ========================================================================= */
describe('checklist keeps unaffected content intact (targeted fix)', () => {
  it('still lists the Name, Size, and Modified columns (table structure unchanged)', () => {
    // These column names appear only in item 7 within the checklist.
    expect(CHECKLIST).toMatch(/Name/);
    expect(CHECKLIST).toMatch(/Size/);
    expect(CHECKLIST).toMatch(/Modified/);
  });

  it('keeps the unrelated build / test / API / Search checklist items', () => {
    expect(CHECKLIST).toMatch(/dotnet build/);
    expect(CHECKLIST).toMatch(/npm test/);
    expect(CHECKLIST).toMatch(/npm run build/);
    expect(CHECKLIST).toMatch(/Upload/);
    expect(CHECKLIST).toMatch(/Search/);
    // The browse API JSON contract item.
    expect(CHECKLIST).toMatch(/entries/);
    expect(CHECKLIST).toMatch(/folderCount/);
    expect(CHECKLIST).toMatch(/fileCount/);
    expect(CHECKLIST).toMatch(/totalSize/);
  });
});

